noncompliant:
// Noncompliant: Missing AttributeUsage
public class MyCustomAttribute : Attribute
{
    public string Description { get; set; }
}

// Noncompliant: No indication where it can be applied
public class ValidatorAttribute : Attribute
{
    public Type ValidatorType { get; set; }
}

compliant:
// Compliant: AttributeUsage specifies valid targets
[AttributeUsage(AttributeTargets.Class | AttributeTargets.Method)]
public class MyCustomAttribute : Attribute
{
    public string Description { get; set; }
}

// Compliant: AttributeUsage with inheritance control
[AttributeUsage(AttributeTargets.Property, AllowMultiple = false, Inherited = true)]
public class ValidatorAttribute : Attribute
{
    public Type ValidatorType { get; set; }
}

// Compliant: AttributeUsage for method-only attribute
[AttributeUsage(AttributeTargets.Method, AllowMultiple = true)]
public class LogAttribute : Attribute
{
    public string Category { get; set; }
}
